@using sv_1e2f2945e5ea49aa9a066615bb7c10e9.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-2">@Task.Priority</span>
        <span class="small text-muted">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)">
                    &larr; Move Left
                </button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_1e2f2945e5ea49aa9a066615bb7c10e9.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }

            @if (showForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="() => showForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100 mt-2" @onclick="() => showForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) formData)
    {
        await OnTaskCreated.InvokeAsync(formData);
        showForm = false;
    }
}

@page "/board"
@rendermode InteractiveServer
@using sv_1e2f2945e5ea49aa9a066615bb7c10e9.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />

    <div class="mb-3">
        <input type="text"
               class="form-control"
               placeholder="Search tasks by title…"
               @bind="searchText"
               @bind:event="oninput" />
    </div>

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="id => MoveTask(id, "In Progress")"
                      OnTaskCreated="data => CreateTask(data, "To Do")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, "To Do")"
                      OnMoveRight="id => MoveTask(id, "Done")"
                      OnTaskCreated="data => CreateTask(data, "In Progress")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, "In Progress")"
                      OnTaskCreated="data => CreateTask(data, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            loading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

