+@using sv_1e2f2945e5ea49aa9a066615bb7c10e9.Services
+
+<div class="col">
+    <div class="card h-100">
+        <div class="card-header d-flex justify-content-between align-items-center">
+            <strong>@ColumnName</strong>
+            <span class="badge bg-secondary">@Tasks.Count</span>
+        </div>
+        <div class="card-body" style="overflow-y: auto;">
+            @foreach (var task in Tasks)
+            {
+                <TaskCard Task="task"
+                          ShowMoveLeft="ShowMoveLeft"
+                          ShowMoveRight="ShowMoveRight"
+                          OnMoveLeft="OnMoveLeft"
+                          OnMoveRight="OnMoveRight" />
+            }
+
+            @if (showForm)
+            {
+                <AddTaskForm OnSave="HandleSave" OnCancel="() => showForm = false" />
+            }
+            else
+            {
+                <button class="btn btn-outline-primary btn-sm w-100 mt-2" @onclick="() => showForm = true">
+                    + Add Task
+                </button>
+            }
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
+    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
+    [Parameter] public bool ShowMoveLeft { get; set; }
+    [Parameter] public bool ShowMoveRight { get; set; }
+    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
+    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
+    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }
+
+    private bool showForm;
+
+    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) formData)
+    {
+        await OnTaskCreated.InvokeAsync(formData);
+        showForm = false;
+    }
+}
